previewCss:
.darma-loader-darma-custom-104 {
  width: 40px;
  aspect-ratio: 1;
  display: grid;
}
.darma-loader-darma-custom-104:before,
.darma-loader-darma-custom-104:after {
  content: "";
  background: var(--loader-color, #ffa500);
  transform-origin: left;
  animation: darma-loader-darma-custom-104-l24 2s infinite;
}
.darma-loader-darma-custom-104:before {
  transform-origin:right;
  --s:-1;
}
@keyframes darma-loader-darma-custom-104-l24 {
   0%,
   10%   {transform:translate(0,0)  scale(1)}
   33%   {transform:translate(calc(var(--s,1)*50%),0)  scale(1)}
   66%   {transform:translate(calc(var(--s,1)*50%),calc(var(--s,1)*-50%))  scale(1)}
   90%,
   100%  {transform:translate(calc(var(--s,1)*50%),calc(var(--s,1)*-50%))  scale(0.5,2)}
}

